class RemoteNode:
    def __init__(self, ip, username, password):
        self.ip = ip
        self.username = username
        self.password = password
        self.client = None

    def connect(self, use_key=False, key_path=None):
        """Establish SSH connection to target host."""
        self.client = paramiko.SSHClient()
        self.client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        try:
            if use_key and key_path:
                print(f"[{self.ip}] Connecting using SSH key: {key_path}...")
                self.client.connect(self.ip, username=self.username, key_filename=key_path, timeout=15)
            else:
                print(f"[{self.ip}] Connecting using password credentials...")
                self.client.connect(self.ip, username=self.username, password=self.password, timeout=15)
            return True
        except Exception as e:
            return False

    def execute(self, command, check_exit=True):
        """Execute command on remote node."""
        if not self.client:
            raise Exception("SSH Client is not connected.")
        
        stdin, stdout, stderr = self.client.exec_command(command)
        exit_status = stdout.channel.recv_exit_status()
        
        out_str = stdout.read().decode('utf-8').strip()
        err_str = stderr.read().decode('utf-8').strip()
        
        if check_exit and exit_status != 0:
            raise Exception(f"Command '{command}' failed with exit code {exit_status}.\nSTDOUT: {out_str}\nSTDERR: {err_str}")
        
        return exit_status, out_str, err_str

    def write_file(self, path, content):
        """Write content to a file on the remote host using SFTP."""
        if not self.client:
            raise Exception("SSH Client is not connected.")
        sftp = self.client.open_sftp()
        try:
            dir_name = os.path.dirname(path)
            self.execute(f"mkdir -p {dir_name}")
            f = sftp.open(path, "w")
            f.write(content)
            f.close()
        finally:
            sftp.close()

    def upload_directory(self, local_path, remote_path):
        """Upload a local directory structure to a remote path using SFTP."""
        if not self.client:
            raise Exception("SSH Client is not connected.")
        sftp = self.client.open_sftp()
        try:
            self.execute(f"rm -rf {remote_path}")
            def recursive_upload(local_dir, remote_dir):
                self.execute(f"mkdir -p {remote_dir}")
                for item in os.listdir(local_dir):
                    l_path = os.path.join(local_dir, item)
                    r_path = remote_dir + "/" + item
                    if os.path.isdir(l_path):
                        recursive_upload(l_path, r_path)
                    else:
                        sftp.put(l_path, r_path)
            recursive_upload(local_path, remote_path)
        finally:
            sftp.close()

    def close(self):
        """Close connection."""
        if self.client:
            self.client.close()

def wait_for_ssh(ip, timeout=120):
    """Wait for SSH to become available on the target host."""
    start_time = time.time()
    while time.time() - start_time < timeout:
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(2)
            s.connect((ip, 22))
            s.close()
            return True
        except Exception:
            time.sleep(2)
    return False

def main():
    print("==========================================================")
    print("              Aura HCI Cluster Provisioner                ")
    print("==========================================================")
    
    script_dir = os.path.dirname(os.path.abspath(__file__))
    
    parser = argparse.ArgumentParser(description="Aura HCI Cluster Provisioner")
    parser.add_argument("--force", "-force", action="store_true", 
                        help="Force provisioning even if the hostname format matches Valkyrie-XXXXXX")
    args = parser.parse_args()
    force_provision = args.force

    priv_key_path = "C:/Users/AuraFlight/.ssh/id_rsa_hci"
    if not os.path.exists(priv_key_path):
        print(f"[FATAL] Private SSH key not found at {priv_key_path}")
        sys.exit(1)
        
    try:
        key = paramiko.RSAKey.from_private_key_file(priv_key_path)
        pub_key_content = f"ssh-rsa {key.get_base64()} root@valkyrie"
    except Exception as e:
        print(f"[FATAL] Failed to load SSH key: {e}")
        sys.exit(1)

    username = DEFAULT_USERNAME
    password = DEFAULT_PASSWORD
    nodes = []

    # Phase 1: Connect and establish SSH mesh & set target static IPs
    print("\n--- Phase 1: Connecting and establishing SSH mesh & setting static IPs ---")
    for idx, target_ip in enumerate(HOSTS):
        dhcp_ip = DHCP_IPS[idx]
        
        # 1. Connect to either target_ip (if already reachable) or dhcp_ip
        node = RemoteNode(target_ip, username, password)
        connected_ip = target_ip
        
        print(f"[{target_ip}] Attempting connection to target IP...")
        if node.connect(use_key=True, key_path=priv_key_path):
            print(f"[{target_ip}] Connected successfully using SSH key on target IP.")
        elif node.connect(use_key=False):
            print(f"[{target_ip}] Connected successfully using password on target IP. Setting up key-based auth...")
            node.execute("mkdir -p /root/.ssh && chmod 700 /root/.ssh")
            node.execute(f"echo '{pub_key_content}' >> /root/.ssh/authorized_keys")
            node.execute("chmod 600 /root/.ssh/authorized_keys")
            node.close()
            node = RemoteNode(target_ip, username, password)
            if not node.connect(use_key=True, key_path=priv_key_path):
                print(f"[FATAL] Key verification failed for {target_ip} after setting it up.")
                sys.exit(1)
        else:
            print(f"[{target_ip}] Target IP not reachable. Connecting to DHCP IP {dhcp_ip}...")
            node = RemoteNode(dhcp_ip, username, password)
            connected_ip = dhcp_ip
            if node.connect(use_key=True, key_path=priv_key_path):
                print(f"[{dhcp_ip}] Connected successfully using SSH key.")
            elif node.connect(use_key=False):
                print(f"[{dhcp_ip}] Connected successfully using password. Setting up key-based auth...")
                node.execute("mkdir -p /root/.ssh && chmod 700 /root/.ssh")
                node.execute(f"echo '{pub_key_content}' >> /root/.ssh/authorized_keys")
                node.execute("chmod 600 /root/.ssh/authorized_keys")
                node.close()
                node = RemoteNode(dhcp_ip, username, password)
                if not node.connect(use_key=True, key_path=priv_key_path):
                    print(f"[FATAL] Key verification failed for {dhcp_ip} after setting it up.")
                    sys.exit(1)
            else:
                print(f"[FATAL] Could not connect to either target IP {target_ip} or DHCP IP {dhcp_ip}.")
                sys.exit(1)

        # 2. Configure static IP if we connected via DHCP IP
        if connected_ip != target_ip:
            try:
                rc_net, conn_name, _ = node.execute("nmcli -t -f TYPE,NAME connection show --active | grep -m1 ethernet | cut -d: -f2")
                conn_name = conn_name.strip()
                if rc_net == 0 and conn_name:
                    print(f"[{dhcp_ip}] Configuring connection '{conn_name}' to static target IP {target_ip}...")
                    node.execute(f"nmcli connection modify '{conn_name}' ipv4.addresses {target_ip}/24 ipv4.gateway 10.10.102.1 ipv4.dns '1.1.1.1,8.8.8.8' ipv4.method manual")
                    node.client.exec_command(f"(sleep 1 && nmcli connection up '{conn_name}') &")
                    node.close()
                    print(f"[{dhcp_ip}] IP migration triggered to {target_ip}. Waiting 10 seconds...")
                    time.sleep(10)
                    
                    # Reconnect on new static IP
                    node = RemoteNode(target_ip, username, password)
                    if not node.connect(use_key=True, key_path=priv_key_path):
                        print(f"[FATAL] Failed to connect to target IP {target_ip} after migration.")
                        sys.exit(1)
                    print(f"[{target_ip}] Reconnected successfully on target static IP.")
            except Exception as e:
                print(f"[{dhcp_ip}] Warning: failed to set static IP: {e}")

        # 3. Hostname check & assignment (generated using target_ip)
        try:
            host_out = node.execute("hostname")[1].strip()
            import hashlib
            h = hashlib.md5(target_ip.encode()).hexdigest()[:6].upper()
            new_hostname = f"Valkyrie-{h}"
            
            if host_out != new_hostname or force_provision:
                print(f"[{target_ip}] Assigning hostname: {new_hostname} (was {host_out})")
                node.execute(f"hostnamectl set-hostname {new_hostname}")
                node.execute(f"grep -q '{new_hostname}' /etc/hosts || echo '127.0.0.1 {new_hostname}' >> /etc/hosts")
                
                # Reboot
                try:
                    node.client.exec_command("reboot")
                except Exception:
                    pass
                node.close()
                print(f"[{target_ip}] Rebooting. Waiting 15 seconds...")
                time.sleep(15)
                if not wait_for_ssh(target_ip):
                    print(f"[FATAL] Node {target_ip} did not boot back online after hostname assignment.")
                    sys.exit(1)
                
                node = RemoteNode(target_ip, username, password)
                if not node.connect(use_key=True, key_path=priv_key_path):
                    print(f"[FATAL] Failed to reconnect to {target_ip} after reboot.")
                    sys.exit(1)
            else:
                print(f"[{target_ip}] Hostname is already correct: {host_out}")
            
            nodes.append(node)
        except Exception as e:
            print(f"[{target_ip}] Bootstrapping failed: {e}")
            node.close()
            sys.exit(1)

    # Phase 2: Host Package Installation & Directory Setup
    print("\n--- Phase 2: Host Package Installation & Directory Setup ---")
    for node in nodes:
        try:
            print(f"[{node.ip}] Installing repositories and packages (dnf-plugins-core, ELRepo, openssl, podman, qemu, libvirt, nfs, lvm2)...")
            node.execute("dnf install -y dnf-plugins-core")
            try:
                node.execute("dnf install -y https://www.elrepo.org/elrepo-release-10.el10.elrepo.noarch.rpm")
            except Exception as e:
                print(f"[{node.ip}] Warning: Failed to install ELRepo RPM: {e}")
            try:
                node.execute("dnf copr enable -y ligenix/enterprise-qemu-spice")
                node.execute("dnf install -y openssl podman qemu-kvm libvirt nfs-utils qemu-kvm-ui-spice lvm2 kmod-drbd9x drbd9x-utils clang lld rust cargo && dnf upgrade -y qemu-kvm\\*", check_exit=True)
                node.execute("dnf downgrade -y seavgabios-bin-1.16.3-7.el10_spice || dnf install -y seavgabios-bin-1.16.3-7.el10_spice", check_exit=True)
                node.execute("mkdir -p /usr/share/qemu && ln -sf /usr/share/seavgabios/vgabios-qxl.bin /usr/share/qemu/vgabios-qxl.bin", check_exit=True)
            except Exception as e:
                print(f"[{node.ip}] Warning: Failed to install with COPR QEMU SPICE, falling back: {e}")
                node.execute("dnf install -y openssl podman qemu-kvm libvirt nfs-utils lvm2 kmod-drbd9x drbd9x-utils clang lld rust cargo", check_exit=True)
            
            print(f"[{node.ip}] Loading DRBD kernel module...")
            node.execute("echo 'drbd' > /etc/modules-load.d/drbd.conf")
            node.execute("modprobe drbd || true")
            
            print(f"[{node.ip}] Enabling KVM ignore_msrs for nested virtualization stability...")
            node.execute("echo 1 > /sys/module/kvm/parameters/ignore_msrs")
            node.execute("echo 'options kvm ignore_msrs=1' > /etc/modprobe.d/kvm.conf")
            
            print(f"[{node.ip}] Starting systemd services (podman, libvirtd, virtqemud, virtnetworkd)...")
            node.execute("systemctl enable --now podman.socket")
            node.execute("systemctl enable --now libvirtd || true")
            node.execute("systemctl enable --now virtqemud virtnetworkd || true")
            
            print(f"[{node.ip}] Configuring firewalld rules...")
            try:
                node.execute("systemctl enable --now firewalld || true")
                node.execute("firewall-cmd --permanent --add-port=443/tcp --add-port=8443/tcp --add-port=8081/tcp "
                             "--add-port=9099/tcp --add-port=9095/tcp --add-port=9091/tcp "
                             "--add-port=9042/tcp --add-port=7000/tcp --add-port=9180/tcp "
                             "--add-port=19042/tcp --add-port=7199/tcp --add-port=2181/tcp "
                             "--add-port=2888/tcp --add-port=3888/tcp "
                             "--add-port=3370/tcp --add-port=3376/tcp --add-port=3366-3367/tcp --add-port=7700-7890/tcp " # Linstor control + DRBD replication
                             "--add-port=2049/tcp --add-port=4789/udp --add-port=5900-5999/tcp")
                node.execute("firewall-cmd --reload")
            except Exception as e:
                print(f"[{node.ip}] Warning: failed to configure firewalld: {e}")

            print(f"[{node.ip}] Creating host storage mount directories...")
            node.execute("mkdir -p /var/lib/hci/zookeeper/data /var/lib/hci/zookeeper/log "
                         "/var/lib/hci/hydra/data /var/lib/linstor /etc/linstor /run/hci "
                         "/etc/hci/spectrum/certs /etc/hci/slate /var/lib/hci/aether/volumes")
        except Exception as e:
            print(f"[{node.ip}] Package/Directory setup failed: {e}")
            sys.exit(1)

    # Phase 3: Synchronizing Configuration Files
    print("\\n--- Phase 3: Synchronizing Configuration Files ---")
    zoo_servers_parts = []
    for idx, ip in enumerate(HOSTS, start=1):
        zoo_servers_parts.append(f"server.{idx}={ip}:2888:3888;2181")
    zoo_servers_str = " ".join(zoo_servers_parts)
    seed_ips = HOSTS[0]

    for idx, node in enumerate(nodes, start=1):
        try:
            print(f"[{node.ip}] Syncing configurations & keys...")
            import hashlib
            hosts_list = []
            for h_idx, ip_addr in enumerate(HOSTS, start=1):
                h = hashlib.md5(ip_addr.encode()).hexdigest()[:6].upper()
                hosts_list.append({
                    "node_id": h_idx,
                    "ip": ip_addr,
                    "hostname": f"Valkyrie-{h}"
                })
            cluster_json_data = {
                "cluster_name": "hci-01",
                "redundancy_factor": 0 if len(HOSTS) == 1 else 1,
                "dfs_engine": "linstor",
                "vip": "",
                "hosts": hosts_list
            }
            cluster_json_str = json.dumps(cluster_json_data, indent=4)
            node.write_file("/etc/hci/cluster.json", cluster_json_str)
            node.write_file("/etc/hci/aether/storage-pools.json", AETHER_STORAGE_JSON)
            node.write_file("/etc/hci/zookeeper/myid", str(idx))
            
            spectrum_env = f"SPECTRUM_API_PORT=8443\nLOCAL_HYPERVISOR_IP={node.ip}\nCLUSTER_SEEDS={seed_ips}"
            node.write_file("/etc/hci/spectrum/spectrum.env", spectrum_env)
            
            hydra_env = f"CASSANDRA_SEEDS={seed_ips}\nLOCAL_IP={node.ip}"
            node.write_file("/etc/hci/hydra/cassandra.env", hydra_env)

            # Write Slate configurations
            local_slate_yml = os.path.join(script_dir, "slate_config", "traefik.yml")
            local_dynamic_yml = os.path.join(script_dir, "slate_config", "dynamic.yml")
            with open(local_slate_yml, "r", encoding="utf-8") as f:
                slate_yml_content = f.read()
            with open(local_dynamic_yml, "r", encoding="utf-8") as f:
                dynamic_yml_content = f.read()
            node.write_file("/etc/hci/slate/traefik.yml", slate_yml_content)
            node.write_file("/etc/hci/slate/dynamic.yml", dynamic_yml_content)

            # Check and load offline Traefik image
            local_tar = os.path.join(script_dir, "traefik.tar")
            if os.path.exists(local_tar):
                print(f"[{node.ip}] Found local traefik.tar. Uploading for offline installation...")
                node.execute("rm -f /tmp/traefik.tar")
                sftp = node.client.open_sftp()
                sftp.put(local_tar, "/tmp/traefik.tar")
                sftp.close()
                print(f"[{node.ip}] Loading Traefik image offline...")
                node.execute("podman load -i /tmp/traefik.tar && rm -f /tmp/traefik.tar")

            # Sync inter-node orchestration SSH keys
            with open(priv_key_path, 'r') as f:
                priv_key_content = f.read()
            node.write_file("/root/.ssh/id_rsa", priv_key_content)
            node.execute("chmod 600 /root/.ssh/id_rsa")
            
            with open(priv_key_path + ".pub", 'r') as f:
                pub_key_file_content = f.read()
            node.write_file("/root/.ssh/id_rsa.pub", pub_key_file_content)
            node.execute("chmod 644 /root/.ssh/id_rsa.pub")

            # Deploy CLIs
            cluster_cli = base64.b64decode(CLUSTER_CLI_B64).decode('utf-8')
            spark_cli = base64.b64decode(SPARK_CLI_B64).decode('utf-8')
            allssh_cli = base64.b64decode(ALLSSH_CLI_B64).decode('utf-8')
            
            node.write_file("/usr/local/bin/cluster", cluster_cli)
            node.execute("chmod +x /usr/local/bin/cluster")
            
            node.write_file("/usr/local/bin/spark", spark_cli)
            node.execute("chmod +x /usr/local/bin/spark")
            
            node.write_file("/usr/local/bin/allssh", allssh_cli)
            node.execute("chmod +x /usr/local/bin/allssh")
            
            nodetool_script = '#!/bin/bash\nexec podman exec -i systemd-hydra-db nodetool "$@"\n'
            node.write_file("/usr/local/bin/nodetool", nodetool_script)
            node.execute("chmod +x /usr/local/bin/nodetool")
            
            vali_cli = base64.b64decode(VALI_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/vali", vali_cli)
            node.execute("chmod +x /usr/local/bin/vali")

            # Deploy valcli CLI
            valcli_cli = base64.b64decode(VALCLI_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/valcli", valcli_cli)
            node.execute("chmod +x /usr/local/bin/valcli")

            # Deploy Catalyst Coordinator
            catalyst_cli = base64.b64decode(CATALYST_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/catalyst", catalyst_cli)
            node.execute("chmod +x /usr/local/bin/catalyst")

            # Deploy Catalyst CLI (catcli)
            catcli_code = base64.b64decode(CATCLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/catcli", catcli_code)
            node.execute("chmod +x /usr/local/bin/catcli")

            catalyst_svc = """[Unit]
Description=Catalyst Task Management Service
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/catalyst
Restart=always
RestartSec=3
User=root
CPUWeight=200
MemoryMax=512M
MemoryHigh=400M
"""
            node.write_file("/etc/systemd/system/catalyst.service", catalyst_svc)

            # Deploy Spark Daemon
            spark_daemon = base64.b64decode(SPARK_DAEMON_B64).decode('utf-8')
            node.write_file("/usr/local/bin/spark-daemon", spark_daemon)
            node.execute("chmod +x /usr/local/bin/spark-daemon")
            
            daemon_svc = """[Unit]
Description=Spark Host Management Daemon
After=network.target

[Service]
Type=simple
ExecStart=/usr/local/bin/spark-daemon
Restart=always
User=root

[Install]
WantedBy=multi-user.target
"""
            node.write_file("/etc/systemd/system/spark-daemon.service", daemon_svc)
            node.execute("systemctl daemon-reload && systemctl enable spark-daemon")

            # Deploy Bifrost Daemon
            bifrost_cli = base64.b64decode(BIFROST_B64).decode('utf-8')
            node.write_file("/usr/local/bin/bifrost", bifrost_cli)
            node.execute("chmod +x /usr/local/bin/bifrost")

            bifrost_svc = """[Unit]
Description=Bifrost VM Lifecycle Management Service
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/bifrost
Restart=always
RestartSec=3
User=root
CPUWeight=100
MemoryMax=512M
MemoryHigh=400M

[Install]
WantedBy=multi-user.target
"""
            node.write_file("/etc/systemd/system/bifrost.service", bifrost_svc)
            node.execute("systemctl enable bifrost")

            # Deploy Dagur task scheduler
            dagur_script = base64.b64decode(DAGUR_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/dagur", dagur_script)
            node.execute("chmod +x /usr/local/bin/dagur")
            
            dagur_svc = """[Unit]
Description=Dagur Task Scheduler Daemon
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/dagur
Restart=always
RestartSec=3
User=root
CPUWeight=100
MemoryMax=512M
MemoryHigh=400M
"""
            node.write_file("/etc/systemd/system/dagur.service", dagur_svc)
            
            # Deploy Mimir health checker
            mimir_script = base64.b64decode(MIMIR_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/mimir", mimir_script)
            node.execute("chmod +x /usr/local/bin/mimir")
            
            mimir_svc = """[Unit]
Description=Mimir Health Checker Daemon
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/mimir
Restart=always
RestartSec=3
User=root
CPUWeight=100
MemoryMax=512M
MemoryHigh=400M
"""
            node.write_file("/etc/systemd/system/mimir.service", mimir_svc)
            
            # Deploy Vali Placement Daemon
            vali_svc = """[Unit]
Description=Vali VM Placement and DRS Daemon
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/vali
Restart=always
RestartSec=3
User=root
CPUWeight=100
MemoryMax=512M
MemoryHigh=400M
"""
            node.write_file("/etc/systemd/system/vali.service", vali_svc)

            # Deploy Gatoway Daemon
            gatoway_cli = base64.b64decode(GATOWAY_B64).decode('utf-8')
            node.write_file("/usr/local/bin/gatoway", gatoway_cli)
            node.execute("chmod +x /usr/local/bin/gatoway")

            gatoway_svc = """[Unit]
Description=Gatoway L2 Network Sync Daemon
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/gatoway
Restart=always
RestartSec=3
User=root
Environment=PYTHONUNBUFFERED=1
CPUWeight=100
MemoryMax=256M
MemoryHigh=200M
"""
            node.write_file("/etc/systemd/system/gatoway.service", gatoway_svc)

            # Deploy Urbosa Daemon
            urbosa_cli = base64.b64decode(URBOSA_B64).decode('utf-8')
            node.write_file("/usr/local/bin/urbosa", urbosa_cli)
            node.execute("chmod +x /usr/local/bin/urbosa")

            urbosa_svc = """[Unit]
Description=Urbosa SDN Logical Router and Overlay Orchestrator
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/urbosa
Restart=always
RestartSec=3
User=root
Environment=PYTHONUNBUFFERED=1
CPUWeight=100
MemoryMax=256M
MemoryHigh=200M
"""
            node.write_file("/etc/systemd/system/urbosa.service", urbosa_svc)

            # Deploy Logos Daemon
            logos_cli = base64.b64decode(LOGOS_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/logos", logos_cli)
            node.execute("chmod +x /usr/local/bin/logos")

            logos_svc = """[Unit]
Description=Logos Distributed Metrics Service
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/logos
Restart=always
RestartSec=3
User=root
Environment=PYTHONUNBUFFERED=1
CPUWeight=100
MemoryMax=256M
MemoryHigh=200M
"""
            node.write_file("/etc/systemd/system/logos.service", logos_svc)

            # Deploy Mipha Daemon
            mipha_cli = base64.b64decode(MIPHA_CLI_B64).decode('utf-8')
            node.write_file("/usr/local/bin/mipha", mipha_cli)
            node.execute("chmod +x /usr/local/bin/mipha")

            mipha_svc = """[Unit]
Description=Mipha HA Cluster Monitor Daemon
After=zookeeper.service

[Service]
Type=simple
ExecStart=/usr/local/bin/mipha
Restart=always
RestartSec=3
User=root
Environment=PYTHONUNBUFFERED=1
CPUWeight=100
MemoryMax=256M
MemoryHigh=200M
"""
            node.write_file("/etc/systemd/system/mipha.service", mipha_svc)

            # Deploy Urbosa Bootstrap Script
            urbosa_bootstrap_script = base64.b64decode(URBOSA_BOOTSTRAP_B64).decode('utf-8')
            node.write_file("/usr/local/bin/urbosa-bootstrap", urbosa_bootstrap_script)
            node.execute("chmod +x /usr/local/bin/urbosa-bootstrap")

            # Deploy Daruk Proxy
            daruk_script = base64.b64decode(DARUK_B64).decode('utf-8')
            node.write_file("/var/lib/hci/hydra/data/daruk.py", daruk_script)

            daruk_svc = """[Unit]
Description=Daruk Database Query Proxy Service
After=hydra-db.service
Requires=hydra-db.service
ConditionPathExists=!/etc/hci/maintenance.state

[Service]
Type=simple
ExecStartPre=-/usr/bin/podman exec systemd-hydra-db pkill -f daruk.py
ExecStart=/usr/bin/podman exec systemd-hydra-db python3 /var/lib/scylla/daruk.py
Restart=always
RestartSec=3
User=root
Environment=PYTHONUNBUFFERED=1
CPUWeight=200
"""
            node.write_file("/etc/systemd/system/daruk.service", daruk_svc)
            node.execute("systemctl daemon-reload")

            # Deploy Agahnim Console Proxy (Rust)
            print(f"[{node.ip}] Deploying and compiling Agahnim console proxy...")
            node.execute("rm -rf /tmp/agahnim_build && mkdir -p /tmp/agahnim_build")
            
            script_dir = os.path.dirname(os.path.abspath(__file__))
            agahnim_local_dir = os.path.join(script_dir, "agahnim")
            node.upload_directory(agahnim_local_dir, "/tmp/agahnim_build")
            
            node.execute("cd /tmp/agahnim_build && cargo build --release", check_exit=True)
            node.execute("cp /tmp/agahnim_build/target/release/agahnim /usr/local/bin/agahnim", check_exit=True)
            node.execute("chmod +x /usr/local/bin/agahnim", check_exit=True)
            node.execute("rm -rf /tmp/agahnim_build")
            
            agahnim_svc = """[Unit]
Description=Agahnim Console Proxy Daemon
After=network.target
ConditionPathExists=!/etc/hci/maintenance.state

[Service]
Type=simple
ExecStart=/usr/local/bin/agahnim 8081
Restart=always
RestartSec=3
User=root
CPUWeight=100
MemoryMax=256M

[Install]
WantedBy=multi-user.target
"""
            node.write_file("/etc/systemd/system/agahnim.service", agahnim_svc)
            node.execute("systemctl daemon-reload && systemctl enable agahnim && systemctl restart agahnim", check_exit=True)


            # Build Spectrum Container Image
            print(f"[{node.ip}] Building Spectrum web UI container image...")
            node.execute("rm -rf /tmp/spectrum_build && mkdir -p /tmp/spectrum_build")
            
            spectrum_server = base64.b64decode(SPECTRUM_SERVER_B64).decode('utf-8')
            spectrum_dockerfile = base64.b64decode(SPECTRUM_DOCKERFILE_B64).decode('utf-8')
            
            node.write_file("/tmp/spectrum_build/server.py", spectrum_server)
            node.write_file("/tmp/spectrum_build/Dockerfile", spectrum_dockerfile)
            
            script_dir = os.path.dirname(os.path.abspath(__file__))
            static_dir = os.path.join(script_dir, "static")
            node.upload_directory(static_dir, "/tmp/spectrum_build/static")
            
            # Compile WebAssembly SPICE LZ decompressor
            print(f"[{node.ip}] Compiling WebAssembly SPICE LZ decompressor...")
            cmd_wasm = (
                "mkdir -p /tmp/spectrum_build/static/vendor/wasm-spice && "
                "clang -target wasm32 -nostdlib -Wl,--no-entry -Wl,--export-all "
                "-o /tmp/spectrum_build/static/vendor/wasm-spice/wasm_spice.wasm "
                "/tmp/spectrum_build/static/spice-html5/src/lz_decompress.c"
            )
            node.execute(cmd_wasm, check_exit=True)
            
            node.execute("podman build -t localhost/spectrum:latest /tmp/spectrum_build", check_exit=True)
            node.execute("rm -rf /tmp/spectrum_build")

        except Exception as e:
            print(f"[{node.ip}] Config synchronization failed: {e}")
            sys.exit(1)

    # Phase 4: Deploying Podman Quadlets
    print("\\n--- Phase 4: Deploying Podman Quadlets ---")
    for idx, node in enumerate(nodes, start=1):
        try:
            print(f"[{node.ip}] Writing Quadlet containers...")
            zoo_quad = QUADLETS["zookeeper"].format(node_id=idx, zoo_servers=zoo_servers_str)
            db_quad = QUADLETS["hydra-db"].format(seeds=seed_ips, node_ip=node.ip)
            aether_quad = QUADLETS["aether"]
            spec_quad = QUADLETS["spectrum"]
            
            node.write_file("/etc/containers/systemd/zookeeper.container", zoo_quad)
            node.write_file("/etc/containers/systemd/hydra-db.container", db_quad)
            node.write_file("/etc/containers/systemd/aether.container", aether_quad)
            node.write_file("/etc/containers/systemd/spectrum.container", spec_quad)
            
            slate_quad = QUADLETS["slate"]
            node.write_file("/etc/containers/systemd/slate.container", slate_quad)
            
            # Controller runs on all nodes for full HA control plane
            controller_quad = QUADLETS["linstor-controller"]
            node.write_file("/etc/containers/systemd/linstor-controller.container", controller_quad)
            
            # Remove legacy Quadlets
            node.execute("rm -f /etc/containers/systemd/spark.container /etc/containers/systemd/odin.container")
            node.execute("systemctl daemon-reload")
        except Exception as e:
            print(f"[{node.ip}] Quadlet deployment failed: {e}")
            sys.exit(1)

    # Phase 5: Starting Core Platform Services
    print("\\n--- Phase 5: Starting Core Platform Services ---")
    for idx, node in enumerate(nodes, start=1):
        print(f"[{node.ip}] Activating services via systemd...")
        
        # Start Controller on all nodes
        try:
            node.execute("systemctl start linstor-controller")
        except Exception as e:
            print(f"[{node.ip}] Warning: linstor-controller failed to start: {e}")
                
        services = ["zookeeper", "hydra-db", "aether", "slate"]
        for svc in services:
            try:
                node.execute(f"systemctl start {svc}")
            except Exception as e:
                print(f"[{node.ip}] Warning: service '{svc}' failed to start: {e}")

        # Basic container check
        time.sleep(2)
        try:
            _, out, _ = node.execute("podman ps --format '{{.Names}}'")
            active_list = out.replace('\n', ', ')
            print(f"[{node.ip}] Active containers: {active_list}")
        except Exception as e:
            print(f"[{node.ip}] Container check failed: {e}")

    # Phase 6: Certificate Generation on Node 1
    # Run openssl command block directly on Node 1 to populate staging folder
    node1 = nodes[0]
    print(f"\\n[{node1.ip}] Generating mTLS certificates locally in /var/lib/hci/certs_staging/...")
    
    cert_gen_sh = f"""#!/bin/bash
mkdir -p /var/lib/hci/certs_staging && chmod 700 /var/lib/hci/certs_staging
cd /var/lib/hci/certs_staging

# 1. CA
openssl genrsa -out ca.key 2048
openssl req -new -x509 -days 3650 -key ca.key -out ca.crt -subj \"/CN=HCI-Root-CA\"

# 2. Client
openssl genrsa -out client.key 2048
openssl req -new -key client.key -out client.csr -subj \"/CN=HCI-Client\"
openssl x509 -req -days 3650 -in client.csr -CA ca.crt -CAkey ca.key -CAcreateserial -out client.crt

# 3. Node certs
for ip in {" ".join(HOSTS)}; do
  cat <<EOF > "node-$ip.cnf"
[req]
distinguished_name = req_distinguished_name
req_extensions = v3_req
prompt = no
[req_distinguished_name]
CN = $ip
[v3_req]
subjectAltName = IP:$ip
EOF
  openssl genrsa -out "node-$ip.key" 2048
  openssl req -new -key "node-$ip.key" -out "node-$ip.csr" -config "node-$ip.cnf"
  openssl x509 -req -days 3650 -in "node-$ip.csr" -CA ca.crt -CAkey ca.key -CAcreateserial -out "node-$ip.crt" -extensions v3_req -extfile "node-$ip.cnf"
done


chmod 600 *.key
"""
    node1.write_file("/tmp/gen_certs.sh", cert_gen_sh)
    node1.execute("chmod +x /tmp/gen_certs.sh && /tmp/gen_certs.sh && rm -f /tmp/gen_certs.sh", check_exit=True)
    print(f"[{node1.ip}] mTLS certificates generated successfully.")

    # Read the generated certificates from node1
    _, ca_crt, _ = node1.execute("cat /var/lib/hci/certs_staging/ca.crt")
    _, client_crt, _ = node1.execute("cat /var/lib/hci/certs_staging/client.crt")
    _, client_key, _ = node1.execute("cat /var/lib/hci/certs_staging/client.key")

    # Distribute certificates to all nodes
    for node in nodes:
        print(f"[{node.ip}] Distributing mTLS certificates...")
        # Create directories
        node.execute("mkdir -p /root/.certs /etc/hci/spark/certs")
        
        # Write client / CA certificates to /root/.certs/
        node.write_file("/root/.certs/ca.crt", ca_crt)
        node.write_file("/root/.certs/client.crt", client_crt)
        node.write_file("/root/.certs/client.key", client_key)
        node.execute("chmod 600 /root/.certs/client.key")

        # Read specific node cert/key from node1
        _, node_crt, _ = node1.execute(f"cat /var/lib/hci/certs_staging/node-{node.ip}.crt")
        _, node_key, _ = node1.execute(f"cat /var/lib/hci/certs_staging/node-{node.ip}.key")

        # Write to /etc/hci/spark/certs/
        node.write_file("/etc/hci/spark/certs/ca.crt", ca_crt)
        node.write_file("/etc/hci/spark/certs/node.crt", node_crt)
        node.write_file("/etc/hci/spark/certs/node.key", node_key)
        node.execute("chmod 600 /etc/hci/spark/certs/node.key")

        # Enable/Restart spark-daemon and restart spectrum container
        print(f"[{node.ip}] Restarting spark-daemon to pick up certificates...")
        try:
            node.execute("systemctl enable spark-daemon")
            node.execute("systemctl restart spark-daemon")
        except Exception as e:
            print(f"[{node.ip}] Warning: Failed to restart spark-daemon: {e}")

        try:
            node.execute("systemctl restart spectrum")
        except Exception as e:
            print(f"[{node.ip}] Warning: Failed to restart spectrum: {e}")

        try:
            node.execute("systemctl restart agahnim")
        except Exception as e:
            print(f"[{node.ip}] Warning: Failed to restart agahnim: {e}")

    for node in nodes:
        node.close()

    print("\\n==========================================================")
    print("      Cluster Bootstrap Completed Successfully!           ")
    print("==========================================================")
    print("Starting configs are copied. You can now SSH into Node 1")
    print("and execute the cluster command to initialize the cluster:")
    print(f"  ssh root@{HOSTS[0]}")
    print(f"  cluster -s {','.join(HOSTS)} --redundancy_factor=1 --vip=10.10.102.130 create")
    print("==========================================================")

if __name__ == "__main__":
    main()
